import{_ as e,o as i,c as s,a2 as t}from"./chunks/framework.BKG_UbFK.js";const k=JSON.parse('{"title":"从已有的 Spatie 安装迁移","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/migration.md","filePath":"zh/guide/migration.md"}'),l={name:"zh/guide/migration.md"};function c(d,a,o,r,n,h){return i(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="从已有的-spatie-安装迁移" tabindex="-1">从已有的 Spatie 安装迁移 <a class="header-anchor" href="#从已有的-spatie-安装迁移" aria-label="Permalink to &quot;从已有的 Spatie 安装迁移&quot;">​</a></h1><p>如果你的应用已经在使用 <code>spatie/laravel-permission</code>，并且已经存在角色、权限和分配关系，<code>clearance:install</code> 会检测并保留它们——只要 <code>roles</code> 表已经存在，它就绝不会运行 Spatie 的迁移。完整的安装流程请参见<a href="/clearance-docs/zh/guide/installation.html">安装</a>。</p><p>安装完成后，使用 <code>clearance:backfill</code> 将 Clearance 自身的元数据补充到你现有的角色和看守器上。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # meta + role scope + guards</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --only=meta</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # just one section</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # preview, no writes</span></span></code></pre></div><h2 id="各部分的作用" tabindex="-1">各部分的作用 <a class="header-anchor" href="#各部分的作用" aria-label="Permalink to &quot;各部分的作用&quot;">​</a></h2><table tabindex="0"><thead><tr><th>部分</th><th>效果</th></tr></thead><tbody><tr><td><code>meta</code></td><td>为每个尚无显示名称的角色，生成一个（标题格式化的角色名）作为 <code>clr_meta</code> 显示名称。</td></tr><tr><td><code>roles</code></td><td>为每个尚无对应记录的角色，生成 <code>clr_role_meta</code> 默认值（<code>scope=global</code>、<code>is_locked=false</code>）。</td></tr><tr><td><code>guards</code></td><td>从 <code>config(&#39;auth.guards&#39;)</code> 导入看守器到 <code>clr_guards</code>，并按 <code>allowed_guard_drivers</code> 过滤。</td></tr></tbody></table><p>使用 <code>--only=&lt;section&gt;</code> 只运行单个部分，而不是全部三个。</p><div class="tip custom-block"><p class="custom-block-title">幂等</p><p>所有部分都是幂等的——重复运行 <code>clearance:backfill</code> 是安全的，不会重复写入或覆盖已有的 <code>clr_*</code> 记录。</p></div><h2 id="边缘情况" tabindex="-1">边缘情况 <a class="header-anchor" href="#边缘情况" aria-label="Permalink to &quot;边缘情况&quot;">​</a></h2><p>该包的代码仓库中有一份更深入的迁移指南，涵盖了本页未总结的边缘情况——特别是当你的数据库中已经存在一个名为 <code>super_admin</code>（或别名如 <code>superadmin</code>、<code>root</code>、<code>owner</code>）的角色，与 Clearance 自身的 <code>super_admin</code> 角色发生冲突时会发生什么，以及关于自定义 <code>Role</code>/<code>Permission</code> 模型子类和看守器导入行为的说明。在对一个已有大量角色数据的生产数据库运行 backfill 之前，请务必先阅读该指南。另请参见<a href="/clearance-docs/zh/features/super-admin.html">超级管理员</a>，了解 <code>clearance:install</code> 期间的别名检测行为。</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="/clearance-docs/zh/guide/installation.html">安装</a>——完整的 <code>clearance:install</code> 流程</li><li><a href="/clearance-docs/zh/api/artisan-commands.html">Artisan 命令</a>——完整的命令参考</li><li><a href="/clearance-docs/zh/guide/architecture.html">架构</a>——backfill 所填充的 <code>clr_*</code> 数据表</li></ul>`,12)])])}const u=e(l,[["render",c]]);export{k as __pageData,u as default};
